import { NextResponse, type NextRequest } from "next/server";
import { ADMIN_COOKIE_NAME } from "@/lib/auth";

/**
 * Middleware protecting /admin/* routes.
 * Exempts /admin/login (the login page) and /api/admin/login (the login API).
 * Runs on Edge runtime — only simple cookie string comparison.
 */
export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Allow access to the login page and login API without authentication
  if (pathname === "/admin/login" || pathname === "/api/admin/login") {
    return NextResponse.next();
  }

  // Check for admin cookie
  const adminCookie = request.cookies.get(ADMIN_COOKIE_NAME);
  if (adminCookie?.value === "authenticated") {
    return NextResponse.next();
  }

  // Redirect unauthenticated users to /admin/login
  const loginUrl = new URL("/admin/login", request.url);
  return NextResponse.redirect(loginUrl);
}

export const config = {
  matcher: ["/admin/:path*", "/api/admin/:path*"],
};

/**
 * Admin authentication helpers — Edge-runtime compatible.
 * Uses a simple password from ADMIN_PASSWORD env var + httpOnly cookie.
 * No Node.js-specific APIs (no Buffer, no crypto beyond what Edge provides).
 */

export const ADMIN_COOKIE_NAME = "trasua-admin";

/** Value stored in the cookie when authenticated */
const ADMIN_TOKEN = "authenticated";

/**
 * Validate a password attempt against ADMIN_PASSWORD env var.
 */
export function validateAdminPassword(password: string): boolean {
  const expected = process.env.ADMIN_PASSWORD;
  if (!expected) return false;
  return password === expected;
}

/**
 * Check whether a raw Cookie header contains a valid admin session token.
 * Edge-compatible: parses cookies manually without Node.js dependencies.
 */
export function checkAdminCookie(cookieHeader: string | null): boolean {
  if (!cookieHeader) return false;

  const cookies = cookieHeader.split(";").reduce(
    (acc, cookie) => {
      const [key, ...rest] = cookie.trim().split("=");
      if (key) acc[key.trim()] = rest.join("=").trim();
      return acc;
    },
    {} as Record<string, string>,
  );

  return cookies[ADMIN_COOKIE_NAME] === ADMIN_TOKEN;
}

/**
 * Build a Set-Cookie header value for admin authentication.
 */
export function buildAdminCookie(): string {
  return `${ADMIN_COOKIE_NAME}=${ADMIN_TOKEN}; Path=/; HttpOnly; SameSite=Lax; Max-Age=86400`;
}

/**
 * Build a Set-Cookie header value that clears the admin cookie.
 */
export function clearAdminCookie(): string {
  return `${ADMIN_COOKIE_NAME}=; Path=/; HttpOnly; SameSite=Lax; Max-Age=0`;
}

/**
 * GET /api/admin/qr-pdf
 *
 * Generates an A4 PDF with a 3×5 grid of QR codes — one per table.
 * Each QR encodes http://SHOP_IP:SHOP_PORT/order?table=N.
 * Protected by admin cookie auth.
 */

import { NextRequest } from "next/server";
import path from "path";
import PDFDocument from "pdfkit";
import QRCode from "qrcode";

import { checkAdminCookie } from "@/lib/auth";

// Force Node.js runtime — pdfkit uses Buffer/fs internally
export const runtime = "nodejs";

export async function GET(request: NextRequest) {
  // ── Auth gate ──────────────────────────────────────────────
  const cookieHeader = request.headers.get("cookie");
  if (!checkAdminCookie(cookieHeader)) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  // ── Env var validation ─────────────────────────────────────
  const shopIp = process.env.SHOP_IP;
  if (!shopIp) {
    return Response.json(
      { error: "SHOP_IP chưa được cấu hình" },
      { status: 400 },
    );
  }
  const shopPort = process.env.SHOP_PORT || "3000";
  const tableCount = Math.max(0, parseInt(process.env.TABLE_COUNT || "15", 10));

  if (tableCount === 0) {
    return Response.json(
      { error: "TABLE_COUNT phải lớn hơn 0" },
      { status: 400 },
    );
  }

  // ── Font validation ────────────────────────────────────────
  const fontPath = path.join(process.cwd(), "public", "fonts", "Inter.ttf");
  try {
    const fs = await import("fs");
    if (!fs.existsSync(fontPath)) {
      return Response.json(
        { error: "Font file not found" },
        { status: 500 },
      );
    }
  } catch {
    return Response.json(
      { error: "Font file not found" },
      { status: 500 },
    );
  }

  try {
    // ── Generate QR buffers ────────────────────────────────────
    const qrBuffers: Buffer[] = [];
    for (let n = 1; n <= tableCount; n++) {
      const url = `http://${shopIp}:${shopPort}/order?table=${n}`;
      const buf = await QRCode.toBuffer(url, {
        width: 300,
        errorCorrectionLevel: "M",
      });
      qrBuffers.push(buf);
    }

    // ── Build PDF ──────────────────────────────────────────────
    // A4: 595.28 × 841.89 pt, margin 40
    const doc = new PDFDocument({ size: "A4", margin: 40 });
    doc.registerFont("Vietnamese", fontPath);

    // Collect PDF chunks (cannot pipe to Response in Next.js)
    const chunks: Buffer[] = [];
    doc.on("data", (chunk: Buffer) => chunks.push(chunk));
    const pdfReady = new Promise<void>((resolve, reject) => {
      doc.on("end", resolve);
      doc.on("error", reject);
    });

    // ── Layout constants ─────────────────────────────────────
    const pageWidth = 595.28;
    const margin = 40;
    const cols = 3;
    const rows = 5;
    const perPage = cols * rows;
    const availableWidth = pageWidth - margin * 2;
    const colWidth = availableWidth / cols;
    const qrSize = 120;
    const rowHeight = 150;
    const titleHeight = 50;

    // ── Render pages ─────────────────────────────────────────
    const totalPages = Math.ceil(tableCount / perPage);

    for (let page = 0; page < totalPages; page++) {
      if (page > 0) doc.addPage();

      // Page title (only first page gets big title)
      if (page === 0) {
        doc
          .font("Vietnamese")
          .fontSize(20)
          .fillColor("#000000")
          .text("QR Code - TraSua", margin, margin, {
            align: "center",
            width: availableWidth,
          });
      }

      const startY = page === 0 ? margin + titleHeight : margin;
      const startIdx = page * perPage;
      const endIdx = Math.min(startIdx + perPage, tableCount);

      for (let i = startIdx; i < endIdx; i++) {
        const localIdx = i - startIdx;
        const col = localIdx % cols;
        const row = Math.floor(localIdx / cols);

        const cellX = margin + col * colWidth;
        const cellY = startY + row * rowHeight;

        // Center QR in column
        const qrX = cellX + (colWidth - qrSize) / 2;

        // Embed QR image
        doc.image(qrBuffers[i], qrX, cellY, {
          width: qrSize,
          height: qrSize,
        });

        // "Bàn N" label — 14pt, centered below QR
        doc
          .font("Vietnamese")
          .fontSize(14)
          .fillColor("#1a1a1a")
          .text(`Bàn ${i + 1}`, cellX, cellY + qrSize + 4, {
            width: colWidth,
            align: "center",
          });

        // "Quét để đặt món" subtitle — 10pt, lighter
        doc
          .font("Vietnamese")
          .fontSize(10)
          .fillColor("#666666")
          .text("Quét để đặt món", cellX, cellY + qrSize + 20, {
            width: colWidth,
            align: "center",
          });
      }
    }

    doc.end();
    await pdfReady;

    const pdfBuffer = Buffer.concat(chunks);

    return new Response(pdfBuffer, {
      status: 200,
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": 'attachment; filename="trasua-qr-codes.pdf"',
        "Cache-Control": "no-store",
      },
    });
  } catch (err) {
    console.error("[qr-pdf] PDF generation failed:", err);
    return Response.json(
      { error: "PDF generation failed" },
      { status: 500 },
    );
  }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/staff/menu
 *
 * Returns all menu items sorted by sortOrder ascending.
 * Used by the add-item modal to display available menu items.
 *
 * Returns: { items: MenuItem[] }
 */
export async function GET() {
  try {
    const menuItems = await prisma.menuItem.findMany({
      orderBy: { sortOrder: 'asc' },
      select: {
        id: true,
        name: true,
        price: true,
        category: true,
        available: true,
        sortOrder: true,
      },
    })

    console.log(
      `[GET /api/staff/menu] Returning ${menuItems.length} menu items`
    )

    return NextResponse.json({ items: menuItems })
  } catch (error) {
    console.error('[GET /api/staff/menu] Failed to fetch menu items:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách món. Vui lòng thử lại.' },
      { status: 500 }
    )
  }
}

import { prisma } from '@/lib/prisma'
import ErrorPage from '@/components/order/ErrorPage'
import MenuView from '@/components/order/MenuView'
import CartUI from '@/components/order/CartUI'
import { CartProvider } from '@/components/order/CartProvider'

const INVALID_TABLE_MSG =
  'Bàn không hợp lệ. Vui lòng scan lại mã QR tại bàn của bạn.'

export default async function OrderPage({
  searchParams,
}: {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>
}) {
  const { table } = await searchParams

  // --- Table validation ---
  const tableStr = typeof table === 'string' ? table : undefined
  const tableNum = tableStr ? parseInt(tableStr, 10) : NaN

  if (!tableStr || isNaN(tableNum)) {
    return <ErrorPage message={INVALID_TABLE_MSG} />
  }

  const tableRecord = await prisma.table.findFirst({
    where: { number: tableNum },
  })

  if (!tableRecord) {
    return <ErrorPage message={INVALID_TABLE_MSG} />
  }

  // --- Fetch all menu items sorted by sortOrder ---
  const menuItems = await prisma.menuItem.findMany({
    orderBy: { sortOrder: 'asc' },
  })

  // Serialize to plain objects for client component boundary
  const items = menuItems.map((item) => ({
    id: item.id,
    name: item.name,
    category: item.category as 'DRINK' | 'FOOD',
    price: item.price,
    description: item.description,
    available: item.available,
    sortOrder: item.sortOrder,
  }))

  const tableInfo = {
    id: tableRecord.id,
    number: tableRecord.number,
    name: tableRecord.name,
  }

  return (
    <div className="min-h-dvh bg-amber-50">
      <CartProvider tableId={tableInfo.id}>
        <CartUI tableId={tableInfo.id} tableNumber={tableInfo.number}>
          <MenuView menuItems={items} table={tableInfo} />
        </CartUI>
      </CartProvider>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { formatVND } from '@/lib/format'
import { useCart } from '@/components/order/CartProvider'

// ─── Types ──────────────────────────────────────────────────────────
export type SerializedMenuItem = {
  id: number
  name: string
  category: 'DRINK' | 'FOOD'
  price: number
  description: string | null
  available: boolean
  sortOrder: number
}

type Tab = 'DRINK' | 'FOOD'

const TABS: { key: Tab; label: string }[] = [
  { key: 'DRINK', label: 'Đồ uống' },
  { key: 'FOOD', label: 'Đồ ăn' },
]

// ─── MenuView ───────────────────────────────────────────────────────
export default function MenuView({
  menuItems,
  table,
}: {
  menuItems: SerializedMenuItem[]
  table: { id: number; number: number; name: string }
}) {
  const { dispatch } = useCart()
  const [activeTab, setActiveTab] = useState<Tab>('DRINK')

  function handleAdd(item: SerializedMenuItem) {
    dispatch({
      type: 'ADD_ITEM',
      payload: { menuItemId: item.id, name: item.name, price: item.price },
    })
  }

  const filtered = menuItems
    .filter((item) => item.category === activeTab)
    .sort((a, b) => a.sortOrder - b.sortOrder)

  return (
    <>
      {/* ── Header ─────────────────────────────────────────────── */}
      <header className="sticky top-0 z-10 bg-amber-50/95 backdrop-blur-sm">
        <div className="flex items-center gap-2 px-4 py-3">
          <span className="text-lg" aria-hidden="true">
            🧋
          </span>
          <h1
            className="text-base font-semibold text-amber-950"
            style={{ textWrap: 'balance' }}
          >
            {table.name}
          </h1>
        </div>

        {/* ── Tab Bar ──────────────────────────────────────────── */}
        <div className="px-4 pb-3">
          <nav
            role="tablist"
            aria-label="Danh mục thực đơn"
            className="inline-flex w-full rounded-xl bg-amber-100/70 p-1"
          >
            {TABS.map((tab) => {
              const isActive = activeTab === tab.key
              return (
                <button
                  key={tab.key}
                  role="tab"
                  aria-selected={isActive}
                  aria-controls={`panel-${tab.key}`}
                  onClick={() => setActiveTab(tab.key)}
                  className={`
                    flex-1 rounded-lg px-4 py-2.5 text-sm font-semibold
                    transition-colors transition-shadow duration-150 ease-out
                    ${
                      isActive
                        ? 'bg-amber-900 text-amber-50 shadow-sm shadow-amber-900/20'
                        : 'text-amber-700 hover:text-amber-900'
                    }
                  `}
                  style={{ minHeight: 44 }}
                >
                  {tab.label}
                </button>
              )
            })}
          </nav>
        </div>

        {/* Bottom edge shadow */}
        <div className="h-px bg-amber-200/50" />
      </header>

      {/* ── Item List ──────────────────────────────────────────── */}
      <main
        id={`panel-${activeTab}`}
        role="tabpanel"
        aria-label={TABS.find((t) => t.key === activeTab)?.label}
        className="px-4 pb-8 pt-4"
      >
        <div className="flex flex-col gap-3">
          {filtered.map((item) => (
            <ItemCard key={item.id} item={item} onAdd={handleAdd} />
          ))}
        </div>

        {filtered.length === 0 && (
          <p
            className="py-12 text-center text-sm text-amber-700/60"
            style={{ textWrap: 'pretty' }}
          >
            Chưa có món nào trong danh mục này.
          </p>
        )}
      </main>
    </>
  )
}

// ─── Item Card ──────────────────────────────────────────────────────
function ItemCard({
  item,
  onAdd,
}: {
  item: SerializedMenuItem
  onAdd: (item: SerializedMenuItem) => void
}) {
  const unavailable = !item.available

  return (
    <div
      className={`
        relative rounded-2xl bg-white p-4
        transition-transform duration-150 ease-out
        ${
          unavailable
            ? 'opacity-55'
            : 'active:scale-[0.96] cursor-pointer'
        }
      `}
      style={{
        boxShadow: unavailable
          ? '0 1px 2px rgba(120, 53, 15, 0.04)'
          : '0 1px 3px rgba(120, 53, 15, 0.06), 0 4px 12px rgba(120, 53, 15, 0.04)',
      }}
      aria-disabled={unavailable || undefined}
    >
      <div className="flex items-start justify-between gap-3">
        {/* Left: name + description */}
        <div className="min-w-0 flex-1">
          <h3
            className={`text-[15px] font-semibold leading-snug ${
              unavailable ? 'text-amber-800/60' : 'text-amber-950'
            }`}
            style={{ textWrap: 'balance' }}
          >
            {item.name}
          </h3>

          {item.description && (
            <p
              className={`mt-1 text-sm leading-relaxed ${
                unavailable
                  ? 'text-amber-700/40'
                  : 'text-amber-700/65'
              }`}
              style={{ textWrap: 'pretty' }}
            >
              {item.description}
            </p>
          )}

          {/* Price */}
          <p
            className={`mt-2 text-sm font-semibold ${
              unavailable ? 'text-amber-700/50' : 'text-amber-800'
            }`}
            style={{ fontVariantNumeric: 'tabular-nums' }}
          >
            {formatVND(item.price)}
          </p>
        </div>

        {/* Right: badge or add affordance */}
        <div className="flex-shrink-0 pt-0.5">
          {unavailable ? (
            <span className="inline-flex items-center rounded-lg bg-amber-100/80 px-2.5 py-1 text-xs font-medium text-amber-700/70">
              Hết hàng
            </span>
          ) : (
            <button
              type="button"
              aria-label={`Thêm ${item.name}`}
              onClick={(e) => {
                e.stopPropagation()
                onAdd(item)
              }}
              className="flex h-9 w-9 items-center justify-center rounded-xl bg-amber-900 text-amber-50 transition-transform duration-150 ease-out active:scale-[0.92]"
              style={{ minHeight: 36, minWidth: 36 }}
            >
              <PlusIcon />
            </button>
          )}
        </div>
      </div>
    </div>
  )
}

