import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { broadcast } from '@/lib/sse'

type OrderItemInput = {
  menuItemId: number
  quantity: number
  notes?: string
}

type OrderRequestBody = {
  tableId: number
  items: OrderItemInput[]
}

export async function POST(request: NextRequest) {
  // ─── Parse body ───────────────────────────────────────────────────
  let body: OrderRequestBody
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { tableId, items } = body

  // ─── Validate shape ───────────────────────────────────────────────
  if (
    typeof tableId !== 'number' ||
    !Array.isArray(items) ||
    items.length === 0
  ) {
    return NextResponse.json(
      { error: 'Dữ liệu đơn hàng không hợp lệ.' },
      { status: 400 },
    )
  }

  // ─── Validate quantities ──────────────────────────────────────────
  for (const item of items) {
    if (
      typeof item.menuItemId !== 'number' ||
      typeof item.quantity !== 'number' ||
      !Number.isInteger(item.quantity) ||
      item.quantity <= 0
    ) {
      return NextResponse.json(
        { error: 'Số lượng phải là số nguyên dương.' },
        { status: 400 },
      )
    }
  }

  // ─── Validate table exists ────────────────────────────────────────
  const table = await prisma.table.findUnique({ where: { id: tableId } })
  if (!table) {
    return NextResponse.json(
      { error: 'Bàn không tồn tại.' },
      { status: 404 },
    )
  }

  // ─── Validate menu items exist and are available ──────────────────
  const menuItemIds = items.map((i) => i.menuItemId)
  const menuItems = await prisma.menuItem.findMany({
    where: { id: { in: menuItemIds } },
  })

  const menuItemMap = new Map(menuItems.map((mi) => [mi.id, mi]))

  // Check for missing items
  const missingIds = menuItemIds.filter((id) => !menuItemMap.has(id))
  if (missingIds.length > 0) {
    return NextResponse.json(
      { error: 'Một số món không tồn tại.', missingItems: missingIds },
      { status: 400 },
    )
  }

  // Check for unavailable items
  const unavailableItems = items
    .filter((i) => {
      const mi = menuItemMap.get(i.menuItemId)
      return mi && !mi.available
    })
    .map((i) => i.menuItemId)

  if (unavailableItems.length > 0) {
    return NextResponse.json(
      { error: 'Một số món đã hết hàng', unavailableItems },
      { status: 409 },
    )
  }

  // ─── Compute totalAmount server-side ──────────────────────────────
  const totalAmount = items.reduce((sum, item) => {
    const menuItem = menuItemMap.get(item.menuItemId)!
    return sum + menuItem.price * item.quantity
  }, 0)

  // ─── Create Order + OrderItems in transaction ─────────────────────
  try {
    const order = await prisma.$transaction(async (tx) => {
      const newOrder = await tx.order.create({
        data: {
          tableId,
          totalAmount,
          status: 'PENDING',
        },
      })

      await tx.orderItem.createMany({
        data: items.map((i) => ({
          orderId: newOrder.id,
          menuItemId: i.menuItemId,
          quantity: i.quantity,
          notes: i.notes || null,
          status: 'PENDING',
        })),
      })

      // Re-fetch with items + menuItem names + table info for response & broadcast
      return tx.order.findUniqueOrThrow({
        where: { id: newOrder.id },
        include: {
          table: true,
          items: {
            include: {
              menuItem: { select: { id: true, name: true, category: true, price: true } },
            },
          },
        },
      })
    })

    // Broadcast new order to all SSE subscribers (no station filter —
    // both bar and kitchen may have relevant items)
    console.log(`[POST /api/order] Broadcasting new-order event for order #${order.id}`)
    broadcast('new-order', order)

    return NextResponse.json({ order }, { status: 201 })
  } catch (error) {
    console.error('[POST /api/order] Transaction failed:', error)
    return NextResponse.json(
      { error: 'Không thể tạo đơn hàng. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

'use client'

import { useState, useCallback, useEffect, useRef } from 'react'
import { formatVND } from '@/lib/format'
import type { ItemStatus } from '@/lib/order-status'
import MenuPickerModal from './MenuPickerModal'

// ─── Types ──────────────────────────────────────────────────────────

interface BillItem {
  id: number
  orderId: number
  menuItemId: number
  name: string
  category: string
  price: number
  quantity: number
  status: string
  notes: string | null
}

interface BillData {
  table: { id: number; number: number; name: string }
  orders: Array<{ id: number }>
  items: BillItem[]
  total: number
}

// ─── Status Config (simplified for bill view) ───────────────────────

const ITEM_STATUS_DISPLAY: Record<
  string,
  { label: string; bg: string; text: string }
> = {
  PENDING: { label: 'Chờ', bg: 'bg-amber-100', text: 'text-amber-800' },
  PREPARING: { label: 'Đang pha', bg: 'bg-orange-100', text: 'text-orange-800' },
  READY: { label: 'Xong', bg: 'bg-emerald-100', text: 'text-emerald-800' },
  SERVED: { label: 'Đã phục vụ', bg: 'bg-slate-100', text: 'text-slate-500' },
  CANCELLED: { label: 'Huỷ', bg: 'bg-red-100', text: 'text-red-700' },
}

const CANCELLABLE_STATUSES: Set<string> = new Set([
  'PENDING',
  'PREPARING',
  'READY',
])

// ─── BillItemRow ────────────────────────────────────────────────────

function BillItemRow({
  item,
  onCancelled,
}: {
  item: BillItem
  onCancelled: () => void
}) {
  const [loading, setLoading] = useState(false)
  const [confirmingCancel, setConfirmingCancel] = useState(false)
  const cancelTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const isCancelled = item.status === 'CANCELLED'
  const canCancel = CANCELLABLE_STATUSES.has(item.status)
  const statusConfig = ITEM_STATUS_DISPLAY[item.status] ?? ITEM_STATUS_DISPLAY.PENDING

  // 3-second auto-reset for cancel confirmation
  useEffect(() => {
    if (confirmingCancel) {
      cancelTimerRef.current = setTimeout(() => {
        setConfirmingCancel(false)
      }, 3000)
    }
    return () => {
      if (cancelTimerRef.current) {
        clearTimeout(cancelTimerRef.current)
        cancelTimerRef.current = null
      }
    }
  }, [confirmingCancel])

  const handleCancelTap = useCallback(async () => {
    if (!confirmingCancel) {
      setConfirmingCancel(true)
      return
    }
    // Second tap — execute cancel
    setLoading(true)
    setConfirmingCancel(false)
    try {
      const res = await fetch(
        `/api/staff/orders/${item.orderId}/items/${item.id}`,
        {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'cancel' }),
        }
      )
      if (!res.ok) {
        const err = await res.json().catch(() => ({}))
        console.error(`[BillView] Cancel failed (${res.status}):`, err.error ?? 'Unknown error')
      } else {
        onCancelled()
      }
    } catch (err) {
      console.error('[BillView] Cancel network error:', err)
    } finally {
      setLoading(false)
    }
  }, [confirmingCancel, item.orderId, item.id, onCancelled])

  return (
    <div
      className={`flex items-center gap-3 py-3 border-b border-amber-100/60 last:border-b-0 transition-opacity duration-200 ${
        isCancelled ? 'opacity-50' : ''
      }`}
    >
      {/* Item info */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2">
          <span
            className={`font-semibold text-base ${
              isCancelled ? 'line-through text-amber-600/50' : 'text-amber-900'
            }`}
          >
            {item.name}
          </span>
          <span className="text-amber-600 font-medium text-sm flex-shrink-0">
            ×{item.quantity}
          </span>
        </div>
        {item.notes && (
          <p className="text-sm text-amber-600/70 mt-0.5 italic truncate">
            📝 {item.notes}
          </p>
        )}
        <div className="flex items-center gap-2 mt-1">
          <span
            className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${statusConfig.bg} ${statusConfig.text}`}
          >
            {statusConfig.label}
          </span>
          <span
            className={`text-xs font-variant-numeric: tabular-nums ${
              isCancelled ? 'text-amber-400 line-through' : 'text-amber-500'
            }`}
            style={{ fontVariantNumeric: 'tabular-nums' }}
          >
            {formatVND(item.price * item.quantity)}
          </span>
        </div>
      </div>

      {/* Cancel button — two-tap confirmation */}
      {canCancel && (
        <button
          onClick={handleCancelTap}
          disabled={loading}
          className={`
            min-h-[44px] px-4 py-2 rounded-xl font-semibold text-sm
            transition-all duration-150 active:scale-[0.96]
            disabled:opacity-50 disabled:cursor-not-allowed
            ${
              confirmingCancel
                ? 'bg-red-600 text-white shadow-md shadow-red-900/20 min-w-[120px]'
                : 'bg-red-50 text-red-600 ring-1 ring-inset ring-red-200 hover:bg-red-100'
            }
          `}
          style={{ transitionProperty: 'background-color, color, transform, box-shadow' }}
        >
          {loading ? (
            <span className="inline-block w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
          ) : confirmingCancel ? (
            'Xác nhận huỷ?'
          ) : (
            'Huỷ'
          )}
        </button>
      )}
    </div>
  )
}

// ─── BillView ───────────────────────────────────────────────────────

export default function BillView({
  tableId,
  onBack,
}: {
  tableId: number
  onBack: () => void
}) {
  const [bill, setBill] = useState<BillData | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [paying, setPaying] = useState(false)
  const [confirmingPay, setConfirmingPay] = useState(false)
  const payTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const [showMenuPicker, setShowMenuPicker] = useState(false)

  // ─── Fetch bill ─────────────────────────────────────────────
  const fetchBill = useCallback(async () => {
    try {
      const res = await fetch(`/api/staff/tables/${tableId}/bill`)
      if (!res.ok) {
        if (res.status === 404) {
          // No unpaid orders — navigate back
          onBack()
          return
        }
        throw new Error(`Lỗi tải hoá đơn (${res.status})`)
      }
      const data = await res.json()
      setBill(data)
      setError(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Lỗi không xác định')
    } finally {
      setLoading(false)
    }
  }, [tableId, onBack])

  useEffect(() => {
    fetchBill()

    // SSE: refetch bill when items change or orders are paid on this table
    const es = new EventSource('/api/staff/orders/stream?station=all')

    es.addEventListener('item-status-change', () => {
      // An item status changed (e.g. cancel from another device) — refetch bill
      fetchBill()
    })

    es.addEventListener('order-paid', (event) => {
      try {
        const { tableId: paidTableId } = JSON.parse(event.data) as { tableId: number }
        if (paidTableId === tableId) {
          console.log('[BillView] SSE order-paid for this table → navigating back')
          onBack()
        }
      } catch {
        // Ignore parse errors
      }
    })

    es.addEventListener('new-order', () => {
      // New order on any table — refetch in case it's this table
      fetchBill()
    })

    return () => {
      es.close()
    }
  }, [fetchBill, tableId, onBack])

  // ─── 3-second auto-reset for pay confirmation ───────────────
  useEffect(() => {
    if (confirmingPay) {
      payTimerRef.current = setTimeout(() => {
        setConfirmingPay(false)
      }, 3000)
    }
    return () => {
      if (payTimerRef.current) {
        clearTimeout(payTimerRef.current)
        payTimerRef.current = null
      }
    }
  }, [confirmingPay])

  // ─── Pay handler — two-tap confirmation ─────────────────────
  const handlePayTap = useCallback(async () => {
    if (!confirmingPay) {
      setConfirmingPay(true)
      return
    }
    // Second tap — execute payment
    setPaying(true)
    setConfirmingPay(false)
    try {
      const res = await fetch(`/api/staff/tables/${tableId}/pay`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      })
      if (!res.ok) {
        const err = await res.json().catch(() => ({}))
        console.error(`[BillView] Pay failed (${res.status}):`, err.error ?? 'Unknown error')
        setPaying(false)
        return
      }
      console.log(`[BillView] Payment successful for table ${tableId}`)
      // Navigate back — table will disappear from checkout list
      onBack()
    } catch (err) {
      console.error('[BillView] Pay network error:', err)
      setPaying(false)
    }
  }, [confirmingPay, tableId, onBack])

  // ─── Item cancelled → refetch bill ──────────────────────────
  const handleItemCancelled = useCallback(() => {
    fetchBill()
  }, [fetchBill])

  // ─── Loading state ──────────────────────────────────────────
  if (loading) {
    return (
      <div className="flex items-center justify-center py-24">
        <span className="inline-block w-8 h-8 border-3 border-amber-300 border-t-amber-700 rounded-full animate-spin" />
      </div>
    )
  }

  // ─── Error state ────────────────────────────────────────────
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center py-24 text-center px-4">
        <span className="text-4xl mb-3 opacity-50">⚠️</span>
        <p className="text-amber-800 font-medium mb-4">{error}</p>
        <button
          onClick={() => { setLoading(true); setError(null); fetchBill() }}
          className="min-h-[44px] px-6 py-2 rounded-xl bg-amber-700 text-amber-50 font-semibold text-sm hover:bg-amber-800 transition-colors active:scale-[0.96]"
          style={{ transitionProperty: 'background-color, transform' }}
        >
          Thử lại
        </button>
      </div>
    )
  }

  if (!bill) return null

  // ─── Separate active vs cancelled items ─────────────────────
  const activeItems = bill.items.filter((i) => i.status !== 'CANCELLED')
  const cancelledItems = bill.items.filter((i) => i.status === 'CANCELLED')

  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-200">
      {/* ─── Back button + table header ──────────────────────── */}
      <div className="flex items-center gap-3 mb-6">
        <button
          onClick={onBack}
          className="min-h-[44px] min-w-[44px] flex items-center justify-center rounded-xl bg-white/60 border border-amber-200/40 text-amber-700 hover:bg-amber-100 transition-colors active:scale-[0.96]"
          style={{ transitionProperty: 'background-color, transform' }}
          aria-label="Quay lại danh sách bàn"
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            strokeWidth={2.5}
            stroke="currentColor"
            className="w-5 h-5"
          >
            <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5 8.25 12l7.5-7.5" />
          </svg>
        </button>
        <div>
          <h2 className="text-2xl font-bold text-amber-900 tracking-tight">
            {bill.table.name}
          </h2>
          <p className="text-sm text-amber-600">
            {bill.orders.length} đơn · {bill.items.length} món
          </p>
        </div>
      </div>

      {/* ─── Bill card ───────────────────────────────────────── */}
      <div className="bg-white/80 backdrop-blur-sm rounded-2xl border border-amber-200/60 shadow-lg shadow-amber-900/5 overflow-hidden">
        {/* Active items */}
        <div className="px-5 py-3">
          {activeItems.length > 0 ? (
            activeItems.map((item) => (
              <BillItemRow
                key={item.id}
                item={item}
                onCancelled={handleItemCancelled}
              />
            ))
          ) : (
            <p className="text-amber-500 text-center py-6">Không có món nào</p>
          )}
        </div>

        {/* Cancelled items (collapsible) */}
        {cancelledItems.length > 0 && (
          <div className="px-5 pb-3 border-t border-amber-100/60">
            <p className="text-xs font-semibold text-amber-500/60 uppercase tracking-wider mt-3 mb-1">
              Đã huỷ
            </p>
            {cancelledItems.map((item) => (
              <BillItemRow
                key={item.id}
                item={item}
                onCancelled={handleItemCancelled}
              />
            ))}
          </div>
        )}

        {/* ─── Add item button ────────────────────────────────── */}
        <div className="px-5 py-3 border-t border-amber-100/60">
          <button
            type="button"
            onClick={() => setShowMenuPicker(true)}
            className="w-full min-h-[44px] flex items-center justify-center gap-2 rounded-xl bg-amber-100/70 border border-amber-200/60 text-amber-800 font-semibold text-sm hover:bg-amber-200/60 transition-colors active:scale-[0.96]"
            style={{ transitionProperty: 'background-color, transform' }}
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-4 h-4">
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
            </svg>
            Thêm món
          </button>
        </div>

        {/* ─── Total + Pay button ────────────────────────────── */}
        <div className="px-5 py-4 bg-gradient-to-r from-amber-50 to-orange-50 border-t border-amber-200/40">
          <div className="flex items-center justify-between mb-4">
            <span className="text-lg font-semibold text-amber-800">
              Tổng cộng
            </span>
            <span
              className="text-2xl font-bold text-amber-900"
              style={{ fontVariantNumeric: 'tabular-nums' }}
            >
              {formatVND(bill.total)}
            </span>
          </div>

          <button
            data-testid="pay-button"
            onClick={handlePayTap}
            disabled={paying || activeItems.length === 0}
            className={`
              w-full min-h-[52px] py-3 rounded-2xl font-bold text-base
              transition-colors duration-200 active:scale-[0.96]
              disabled:opacity-50 disabled:cursor-not-allowed
              ${
                confirmingPay
                  ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/30'
                  : 'bg-amber-700 text-amber-50 hover:bg-amber-800 shadow-md shadow-amber-900/20'
              }
            `}
            style={{ transitionProperty: 'background-color, color, transform, box-shadow' }}
          >
            {paying ? (
              <span className="inline-flex items-center gap-2">
                <span className="inline-block w-5 h-5 border-2 border-current border-t-transparent rounded-full animate-spin" />
                Đang xử lý…
              </span>
            ) : confirmingPay ? (
              'Xác nhận thanh toán? ✓'
            ) : (
              `Đã thanh toán · ${formatVND(bill.total)}`
            )}
          </button>
        </div>
      </div>

      {/* ─── Menu Picker Modal ───────────────────────────────── */}
      <MenuPickerModal
        orderId={bill.orders[bill.orders.length - 1].id}
        tableId={tableId}
        isOpen={showMenuPicker}
        onClose={() => setShowMenuPicker(false)}
        onSuccess={fetchBill}
      />
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback, useRef } from 'react'
import { formatVND } from '@/lib/format'

// ─── Types ──────────────────────────────────────────────────────────

interface MenuItem {
  id: number
  name: string
  price: number
  category: 'DRINK' | 'FOOD'
  available: boolean
  sortOrder: number
}

type Tab = 'DRINK' | 'FOOD'

const TABS: { key: Tab; label: string }[] = [
  { key: 'DRINK', label: 'Đồ uống' },
  { key: 'FOOD', label: 'Đồ ăn' },
]

// ─── Props ──────────────────────────────────────────────────────────

interface MenuPickerModalProps {
  orderId: number
  tableId: number
  isOpen: boolean
  onClose: () => void
  onSuccess: () => void
}

// ─── MenuPickerModal ────────────────────────────────────────────────

export default function MenuPickerModal({
  orderId,
  tableId,
  isOpen,
  onClose,
  onSuccess,
}: MenuPickerModalProps) {
  const [menuItems, setMenuItems] = useState<MenuItem[]>([])
  const [activeTab, setActiveTab] = useState<Tab>('DRINK')
  const [loadingMenu, setLoadingMenu] = useState(false)
  const [menuError, setMenuError] = useState<string | null>(null)

  // Selection state — single item at a time
  const [selectedItem, setSelectedItem] = useState<MenuItem | null>(null)
  const [quantity, setQuantity] = useState(1)
  const [notes, setNotes] = useState('')

  const [submitting, setSubmitting] = useState(false)
  const [submitError, setSubmitError] = useState<string | null>(null)

  // Visibility + animation state
  const [visible, setVisible] = useState(false)
  const overlayRef = useRef<HTMLDivElement>(null)

  // ─── Fetch menu when opened ─────────────────────────────────
  useEffect(() => {
    if (!isOpen) return

    setLoadingMenu(true)
    setMenuError(null)
    setSelectedItem(null)
    setQuantity(1)
    setNotes('')
    setSubmitError(null)
    setActiveTab('DRINK')

    // Trigger enter animation
    requestAnimationFrame(() => setVisible(true))

    fetch('/api/staff/menu')
      .then(async (res) => {
        if (!res.ok) throw new Error(`Lỗi tải thực đơn (${res.status})`)
        const data = await res.json()
        setMenuItems(data.items ?? [])
        console.log(`[MenuPickerModal] Loaded ${data.items?.length ?? 0} menu items`)
      })
      .catch((err) => {
        console.error('[MenuPickerModal] Menu fetch error:', err)
        setMenuError(err instanceof Error ? err.message : 'Lỗi không xác định')
      })
      .finally(() => setLoadingMenu(false))
  }, [isOpen])

  // ─── Close with exit animation ──────────────────────────────
  const handleClose = useCallback(() => {
    setVisible(false)
    // Wait for exit animation before actually closing
    setTimeout(() => {
      onClose()
    }, 200)
  }, [onClose])

  // ─── Click outside → dismiss ────────────────────────────────
  const handleOverlayClick = useCallback(
    (e: React.MouseEvent) => {
      if (e.target === overlayRef.current) {
        handleClose()
      }
    },
    [handleClose]
  )

  // ─── Select an item ─────────────────────────────────────────
  const handleSelectItem = useCallback((item: MenuItem) => {
    if (!item.available) return
    setSelectedItem(item)
    setQuantity(1)
    setNotes('')
    setSubmitError(null)
  }, [])

  // ─── Quantity adjusters ─────────────────────────────────────
  const handleDecrement = useCallback(() => {
    setQuantity((q) => Math.max(1, q - 1))
  }, [])

  const handleIncrement = useCallback(() => {
    setQuantity((q) => q + 1)
  }, [])

  // ─── Submit ─────────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    if (!selectedItem) return

    setSubmitting(true)
    setSubmitError(null)

    try {
      const res = await fetch(`/api/staff/orders/${orderId}/items`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          items: [
            {
              menuItemId: selectedItem.id,
              quantity,
              ...(notes.trim() ? { notes: notes.trim() } : {}),
            },
          ],
        }),
      })

      if (!res.ok) {
        const data = await res.json().catch(() => ({}))
        if (res.status === 409) {
          setSubmitError(data.error ?? 'Đơn hàng đã thanh toán hoặc món đã hết hàng.')
        } else {
          setSubmitError(data.error ?? `Lỗi thêm món (${res.status})`)
        }
        return
      }

      console.log(
        `[MenuPickerModal] Added ${quantity}× ${selectedItem.name} to order #${orderId}`
      )
      onSuccess()
      handleClose()
    } catch (err) {
      console.error('[MenuPickerModal] Submit error:', err)
      setSubmitError('Lỗi kết nối. Vui lòng thử lại.')
    } finally {
      setSubmitting(false)
    }
  }, [selectedItem, quantity, notes, orderId, onSuccess, handleClose])

  // ─── Don't render if not open ───────────────────────────────
  if (!isOpen) return null

  const filtered = menuItems
    .filter((item) => item.category === activeTab)
    .sort((a, b) => a.sortOrder - b.sortOrder)

  return (
    /* ─── Overlay (dimmed backdrop) ─────────────────────────── */
    <div
      ref={overlayRef}
      onClick={handleOverlayClick}
      className={`
        fixed inset-0 z-50 flex items-end justify-center
        transition-colors duration-200
        ${visible ? 'bg-black/40' : 'bg-black/0'}
      `}
      style={{ transitionProperty: 'background-color' }}
    >
      {/* ─── Modal content (slide up from bottom) ──────────── */}
      <div
        className={`
          w-full max-w-lg bg-amber-50 rounded-t-3xl
          overflow-hidden flex flex-col
          transition-transform duration-250 ease-out
          ${visible ? 'translate-y-0' : 'translate-y-full'}
        `}
        style={{
          maxHeight: '85vh',
          transitionProperty: 'transform',
          transitionTimingFunction: visible
            ? 'cubic-bezier(0.16, 1, 0.3, 1)'   /* ease-out for enter */
            : 'cubic-bezier(0.4, 0, 1, 1)',      /* ease-in for exit */
          transitionDuration: visible ? '300ms' : '200ms',
        }}
      >
        {/* ─── Drag handle + Header ────────────────────────── */}
        <div className="sticky top-0 z-10 bg-amber-50">
          <div className="flex justify-center pt-3 pb-1">
            <div className="w-10 h-1 rounded-full bg-amber-300/60" />
          </div>
          <div className="flex items-center justify-between px-5 pb-3">
            <h2 className="text-lg font-bold text-amber-900" style={{ textWrap: 'balance' as never }}>
              Thêm món
            </h2>
            <button
              onClick={handleClose}
              className="min-h-[44px] min-w-[44px] flex items-center justify-center rounded-xl text-amber-600 hover:text-amber-900 hover:bg-amber-100 transition-colors active:scale-[0.96]"
              style={{ transitionProperty: 'background-color, color, transform' }}
              aria-label="Đóng"
            >
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18 18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* ─── Tab Bar ─────────────────────────────────────── */}
          <div className="px-5 pb-3">
            <nav
              role="tablist"
              aria-label="Danh mục thực đơn"
              className="inline-flex w-full rounded-xl bg-amber-100/70 p-1"
            >
              {TABS.map((tab) => {
                const isActive = activeTab === tab.key
                return (
                  <button
                    key={tab.key}
                    role="tab"
                    aria-selected={isActive}
                    aria-controls={`modal-panel-${tab.key}`}
                    onClick={() => setActiveTab(tab.key)}
                    className={`
                      flex-1 rounded-lg px-4 py-2.5 text-sm font-semibold
                      transition-colors duration-150 ease-out
                      ${
                        isActive
                          ? 'bg-amber-900 text-amber-50 shadow-sm shadow-amber-900/20'
                          : 'text-amber-700 hover:text-amber-900'
                      }
                    `}
                    style={{ minHeight: 44, transitionProperty: 'background-color, color, box-shadow' }}
                  >
                    {tab.label}
                  </button>
                )
              })}
            </nav>
          </div>
          <div className="h-px bg-amber-200/50" />
        </div>

        {/* ─── Scrollable item list ─────────────────────────── */}
        <div
          id={`modal-panel-${activeTab}`}
          role="tabpanel"
          aria-label={TABS.find((t) => t.key === activeTab)?.label}
          className="flex-1 overflow-y-auto px-5 py-4"
          style={{ WebkitOverflowScrolling: 'touch' }}
        >
          {loadingMenu ? (
            <div className="flex items-center justify-center py-16">
              <span className="inline-block w-7 h-7 border-3 border-amber-300 border-t-amber-700 rounded-full animate-spin" />
            </div>
          ) : menuError ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <span className="text-3xl mb-2 opacity-50">⚠️</span>
              <p className="text-amber-700 text-sm">{menuError}</p>
            </div>
          ) : filtered.length === 0 ? (
            <p className="py-12 text-center text-sm text-amber-700/60" style={{ textWrap: 'pretty' as never }}>
              Chưa có món nào trong danh mục này.
            </p>
          ) : (
            <div className="flex flex-col gap-2">
              {filtered.map((item) => {
                const isSelected = selectedItem?.id === item.id
                const unavailable = !item.available
                return (
                  <button
                    key={item.id}
                    type="button"
                    disabled={unavailable}
                    onClick={() => handleSelectItem(item)}
                    className={`
                      w-full text-left rounded-2xl p-4
                      transition-all duration-150 ease-out
                      disabled:cursor-not-allowed
                      ${
                        unavailable
                          ? 'opacity-50 bg-amber-100/40'
                          : isSelected
                          ? 'bg-amber-900/10 ring-2 ring-amber-700/40 active:scale-[0.98]'
                          : 'bg-white active:scale-[0.96]'
                      }
                    `}
                    style={{
                      transitionProperty: 'transform, background-color, box-shadow, opacity',
                      boxShadow: unavailable
                        ? 'none'
                        : isSelected
                        ? '0 2px 8px rgba(120, 53, 15, 0.08)'
                        : '0 1px 3px rgba(120, 53, 15, 0.06), 0 1px 2px rgba(120, 53, 15, 0.04)',
                    }}
                    aria-disabled={unavailable || undefined}
                    aria-pressed={isSelected}
                  >
                    <div className="flex items-center justify-between gap-3">
                      <div className="min-w-0 flex-1">
                        <span
                          className={`text-[15px] font-semibold leading-snug ${
                            unavailable ? 'text-amber-800/50' : 'text-amber-950'
                          }`}
                        >
                          {item.name}
                        </span>
                        <div className="flex items-center gap-2 mt-1">
                          <span
                            className={`text-sm font-semibold ${
                              unavailable ? 'text-amber-700/40' : 'text-amber-800'
                            }`}
                            style={{ fontVariantNumeric: 'tabular-nums' }}
                          >
                            {formatVND(item.price)}
                          </span>
                        </div>
                      </div>
                      {unavailable ? (
                        <span className="inline-flex items-center rounded-lg bg-amber-200/60 px-2.5 py-1 text-xs font-medium text-amber-600">
                          Hết hàng
                        </span>
                      ) : isSelected ? (
                        <span className="flex h-6 w-6 items-center justify-center rounded-full bg-amber-800 text-amber-50">
                          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-3.5 h-3.5">
                            <path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" />
                          </svg>
                        </span>
                      ) : null}
                    </div>
                  </button>
                )
              })}
            </div>
          )}
        </div>

        {/* ─── Selection detail + submit ────────────────────── */}
        {selectedItem && (
          <div className="border-t border-amber-200/60 bg-gradient-to-r from-amber-50 to-orange-50 px-5 py-4">
            {/* Selected item name */}
            <div className="flex items-center justify-between mb-3">
              <span className="text-sm font-semibold text-amber-900 truncate flex-1 mr-3">
                {selectedItem.name}
              </span>
              <span
                className="text-sm font-bold text-amber-800 flex-shrink-0"
                style={{ fontVariantNumeric: 'tabular-nums' }}
              >
                {formatVND(selectedItem.price * quantity)}
              </span>
            </div>

            {/* Quantity selector */}
            <div className="flex items-center gap-3 mb-3">
              <span className="text-sm text-amber-700">Số lượng</span>
              <div className="flex items-center gap-1 bg-white rounded-xl border border-amber-200/60 p-0.5">
                <button
                  type="button"
                  onClick={handleDecrement}
                  disabled={quantity <= 1}
                  className="min-h-[44px] min-w-[44px] flex items-center justify-center rounded-lg text-amber-700 hover:bg-amber-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors active:scale-[0.96]"
                  style={{ transitionProperty: 'background-color, transform' }}
                  aria-label="Giảm số lượng"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-4 h-4">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h14" />
                  </svg>
                </button>
                <span
                  className="min-w-[40px] text-center text-lg font-bold text-amber-900"
                  style={{ fontVariantNumeric: 'tabular-nums' }}
                >
                  {quantity}
                </span>
                <button
                  type="button"
                  onClick={handleIncrement}
                  className="min-h-[44px] min-w-[44px] flex items-center justify-center rounded-lg text-amber-700 hover:bg-amber-100 transition-colors active:scale-[0.96]"
                  style={{ transitionProperty: 'background-color, transform' }}
                  aria-label="Tăng số lượng"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-4 h-4">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                  </svg>
                </button>
              </div>
            </div>

            {/* Notes input */}
            <input
              type="text"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Ghi chú (tuỳ chọn)"
              className="w-full rounded-xl border border-amber-200/60 bg-white px-4 py-3 text-sm text-amber-900 placeholder:text-amber-400 focus:outline-none focus:ring-2 focus:ring-amber-600/30 mb-3"
              style={{ minHeight: 44 }}
            />

            {/* Error message */}
            {submitError && (
              <p className="text-sm text-red-600 mb-3 bg-red-50 rounded-lg px-3 py-2">
                {submitError}
              </p>
            )}

            {/* Action buttons */}
            <div className="flex gap-3">
              <button
                type="button"
                onClick={handleClose}
                disabled={submitting}
                className="flex-1 min-h-[48px] rounded-2xl bg-white border border-amber-200/60 text-amber-700 font-semibold text-sm hover:bg-amber-100 transition-colors active:scale-[0.96] disabled:opacity-50"
                style={{ transitionProperty: 'background-color, transform' }}
              >
                Huỷ
              </button>
              <button
                type="button"
                onClick={handleSubmit}
                disabled={submitting}
                className="flex-[2] min-h-[48px] rounded-2xl bg-amber-700 text-amber-50 font-bold text-sm hover:bg-amber-800 shadow-md shadow-amber-900/20 transition-colors active:scale-[0.96] disabled:opacity-50 disabled:cursor-not-allowed"
                style={{ transitionProperty: 'background-color, transform, box-shadow' }}
              >
                {submitting ? (
                  <span className="inline-flex items-center gap-2">
                    <span className="inline-block w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                    Đang thêm…
                  </span>
                ) : (
                  `Thêm · ${formatVND(selectedItem.price * quantity)}`
                )}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

import { PrismaClient } from '../generated/prisma/client'
import { PrismaBetterSqlite3 } from '@prisma/adapter-better-sqlite3'

const prisma = new PrismaClient({
  adapter: new PrismaBetterSqlite3({ url: 'file:prisma/dev.db' }),
})

async function main() {
  // Clear tables in reverse dependency order to avoid FK constraint violations
  await prisma.orderItem.deleteMany()
  await prisma.order.deleteMany()
  await prisma.menuItem.deleteMany()
  await prisma.table.deleteMany()

  // ─── Seed Menu Items ──────────────────────────────────────────────
  const drinks = [
    { name: 'Trà sữa trân châu', price: 35000 },
    { name: 'Trà sữa matcha', price: 40000 },
    { name: 'Trà sữa socola', price: 38000 },
    { name: 'Trà sữa khoai môn', price: 38000 },
    { name: 'Trà đào cam sả', price: 35000 },
    { name: 'Trà vải', price: 32000 },
    { name: 'Trà chanh leo', price: 30000 },
    { name: 'Cà phê sữa đá', price: 29000 },
    { name: 'Sinh tố bơ', price: 40000 },
    { name: 'Sinh tố xoài', price: 35000 },
    { name: 'Nước ép cam', price: 28000 },
    { name: 'Soda chanh', price: 25000 },
  ]

  const foods = [
    { name: 'Bánh tráng trộn', price: 25000 },
    { name: 'Khoai tây chiên', price: 30000 },
    { name: 'Gà viên chiên', price: 35000 },
    { name: 'Xúc xích nướng', price: 28000 },
    { name: 'Bánh mì bơ tỏi', price: 20000 },
    { name: 'Phô mai que', price: 32000 },
  ]

  const menuItems = await Promise.all([
    ...drinks.map((item, i) =>
      prisma.menuItem.create({
        data: {
          name: item.name,
          category: 'DRINK',
          price: item.price,
          sortOrder: i + 1,
        },
      })
    ),
    ...foods.map((item, i) =>
      prisma.menuItem.create({
        data: {
          name: item.name,
          category: 'FOOD',
          price: item.price,
          sortOrder: i + 1,
        },
      })
    ),
  ])

  // ─── Seed Tables ──────────────────────────────────────────────────
  const tables = await Promise.all(
    Array.from({ length: 15 }, (_, i) =>
      prisma.table.create({
        data: {
          number: i + 1,
          name: `Bàn ${i + 1}`,
        },
      })
    )
  )

  console.log(`Seeded ${menuItems.length} menu items and ${tables.length} tables`)
}

main()
  .catch((e) => {
    console.error(e)
    process.exit(1)
  })
  .finally(async () => {
    await prisma.$disconnect()
  })

/**
 * SSE Subscriber Registry
 *
 * In-memory registry of SSE connections, cached on globalThis to survive
 * Next.js HMR reloads (same pattern as Prisma singleton in src/lib/prisma.ts).
 *
 * Subscribers can be filtered by station (bar/kitchen) so broadcasts only
 * reach relevant clients.
 */

export interface SSESubscriber {
  controller: ReadableStreamDefaultController
  station: string | null
}

interface SSERegistry {
  subscribers: Set<SSESubscriber>
}

const globalForSSE = globalThis as unknown as { __sseRegistry: SSERegistry }

function getRegistry(): SSERegistry {
  if (!globalForSSE.__sseRegistry) {
    globalForSSE.__sseRegistry = { subscribers: new Set() }
    console.log('[SSE] Registry initialized')
  }
  return globalForSSE.__sseRegistry
}

/**
 * Register a new SSE subscriber.
 * @param controller - ReadableStream controller to write SSE events to
 * @param station - Optional station filter ('bar', 'kitchen', or null for all)
 * @returns The subscriber object (for later removal)
 */
export function addSubscriber(
  controller: ReadableStreamDefaultController,
  station: string | null = null
): SSESubscriber {
  const registry = getRegistry()
  const subscriber: SSESubscriber = { controller, station }
  registry.subscribers.add(subscriber)
  console.log(
    `[SSE] Subscriber connected (station=${station ?? 'all'}, total=${registry.subscribers.size})`
  )
  return subscriber
}

/**
 * Remove a subscriber from the registry.
 * Call this when the client disconnects.
 */
export function removeSubscriber(subscriber: SSESubscriber): void {
  const registry = getRegistry()
  registry.subscribers.delete(subscriber)
  console.log(
    `[SSE] Subscriber disconnected (station=${subscriber.station ?? 'all'}, total=${registry.subscribers.size})`
  )
}

/**
 * Broadcast an SSE event to all matching subscribers.
 * @param event - SSE event name (e.g. 'order-update', 'item-status-change')
 * @param data - JSON-serializable payload
 * @param station - If set, only send to subscribers matching this station (or those with no station filter)
 */
export function broadcast(
  event: string,
  data: unknown,
  station?: string | null
): void {
  const registry = getRegistry()
  const payload = `event: ${event}\ndata: ${JSON.stringify(data)}\n\n`
  const encoder = new TextEncoder()
  const encoded = encoder.encode(payload)

  let sent = 0
  const toRemove: SSESubscriber[] = []

  for (const subscriber of registry.subscribers) {
    // Filter: if station is specified, only send to subscribers with matching station or no filter
    if (station && subscriber.station && subscriber.station !== station) {
      continue
    }

    try {
      subscriber.controller.enqueue(encoded)
      sent++
    } catch {
      // Controller is closed or errored — mark for cleanup
      toRemove.push(subscriber)
    }
  }

  // Clean up dead connections
  for (const dead of toRemove) {
    registry.subscribers.delete(dead)
    console.log(
      `[SSE] Removed dead subscriber (station=${dead.station ?? 'all'})`
    )
  }

  console.log(
    `[SSE] Broadcast event="${event}" station=${station ?? 'all'} sent=${sent} cleaned=${toRemove.length}`
  )
}

/**
 * Get the current subscriber count. Useful for health checks and debugging.
 */
export function getSubscriberCount(): number {
  return getRegistry().subscribers.size
}

const vndFormatter = new Intl.NumberFormat('vi-VN')

/**
 * Format a VND price integer into a human-readable string.
 * Example: 45000 → '45,000đ'
 */
export function formatVND(price: number): string {
  return `${vndFormatter.format(price)}đ`
}

